#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=300005;
struct node
{
	int v,val;
	bool operator<(const node other) const
	{
		return val>other.val;
	}
};
int n,m,ans[N],vis[N],a[N],mx;
vector<node> g[N];
void dij()
{
	priority_queue<node> pq;
	memset(ans,0x3f,sizeof(ans));
	ans[1]=0;
	pq.push(node{1,0});
	while(!pq.empty())
	{
		node t=pq.top();
		pq.pop();
		int u=t.v;
		if(vis[u]) continue;
		vis[u]=1;
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].val;
			if(!vis[v]&&ans[u]+w<ans[v])
			{
				ans[v]=ans[u]+w;
				pq.push(node{v,ans[v]});
			}
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		mx=max(mx,a[i]);
	}
	for(int i=1;i<=n;i++)
	{
		g[i].push_back(node{i+n,a[i]});
		g[i+n].push_back(node{i+n+n,mx-a[i]});
//		cout<<i<<" "<<i+n<<"  "<<-a[i]<<"\n"<<i+n<<" "<<i+n+n<<"  "<<a[i]<<"\n";
	}
	for(int i=1;i<=m;i++)
	{
		int u,v,op;
		cin>>u>>v>>op;
		if(op==2)
		{
			g[v].push_back(node{u,0});
			g[n+v].push_back(node{n+u,0});
			g[n+n+v].push_back(node{n+n+u,0});
		}
		g[u].push_back(node{v,0});
		g[n+u].push_back(node{n+v,0});
		g[n+n+u].push_back(node{n+n+v,0});
	}
	dij();
	cout<<mx-ans[n*3];
	return 0;
}
